use strict;
use warnings;
use PDF::API2;
use CAM::PDF;
use Text::PDF::Text;

sub extract_info {
    my ($file) = @_;

    # Open the PDF file
    my $pdf = CAM::PDF->new($file);

    # Extract metadata
    my $info = $pdf->getPageInfo(1);
    my $author = $info->{"Author"};
    my $date = $info->{"ModDate"};

    # Print metadata
    print "Author: $author\n";
    print "Date: $date\n";

    # Extract tables
    my $text = Text::PDF::Text->new();
    my $pages = $pdf->numPages();
    foreach my $i (1 .. $pages) {
        my $page_text = $text->getPageText( $pdf, $i, 1 );
        if ($page_text =~ /\btable\b/i) {
            print "Table found on page $i:\n$1\n" if $page_text =~ /table\s+([\s\S]+?table)/i;
        }
    }
}

# Usage
my $pdf_file = 'example.pdf';  # Replace with your PDF file path
extract_info($pdf_file);
